import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { getAllRFQs } from "../api/axios";

const statusBadge = (status) => {
  const badges = {
    active: "bg-green-100 text-[#16a34a]",
    closed: "bg-gray-100 text-gray-700",
    force_closed: "bg-red-100 text-[#dc2626]",
  };

  const labels = {
    active: "Active",
    closed: "Closed",
    force_closed: "Force Closed",
  };

  const label = status === "active" ? "Active" : status === "force_closed" ? "Force Closed" : "Closed";
  return <span className={`inline-flex rounded-full px-3 py-1 text-xs font-semibold ${badges[status] || badges.closed}`}>{labels[status] || label}</span>;
};

const formatDateTime = (dt) => {
  if (!dt) return "";
  const d = new Date(dt);
  return d.toLocaleString("en-GB", {
    day: "2-digit",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
};

const AuctionList = () => {
  const navigate = useNavigate();
  const [rfqs, setRfqs] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchRFQs = async () => {
    setLoading(true);
    try {
      const data = await getAllRFQs();
      setRfqs(data);
    } catch (e) {
      setRfqs([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRFQs();
    const interval = setInterval(fetchRFQs, 30000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="min-h-screen bg-[#f1f5f9] px-4 py-8 sm:px-6">
      <div className="mx-auto w-full max-w-6xl">
        <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <h1 className="text-2xl font-bold text-[#1e3a5f]">RFQ Auctions</h1>
          <button
            className="w-full rounded-lg bg-[#1e3a5f] px-5 py-2.5 text-sm font-semibold text-white shadow-md transition hover:bg-slate-800 sm:w-auto"
            onClick={() => navigate("/create-rfq")}
          >
            Create New RFQ
          </button>
        </div>

        <div className="overflow-hidden rounded-xl bg-white shadow-lg">
          {loading ? (
            <div className="p-10 text-center text-sm text-gray-500">Loading auctions...</div>
          ) : rfqs.length === 0 ? (
            <div className="flex flex-col items-center justify-center gap-3 p-12 text-center">
              <svg className="h-10 w-10 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M3 7h18M5 7v11a2 2 0 002 2h10a2 2 0 002-2V7M9 11h6" />
              </svg>
              <p className="text-base font-medium text-gray-600">No auctions yet</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="min-w-full border-collapse">
                <thead>
                  <tr className="bg-[#1e3a5f] text-left text-white">
                    <th className="px-4 py-3 text-sm font-semibold">RFQ Name</th>
                    <th className="px-4 py-3 text-sm font-semibold">Reference ID</th>
                    <th className="px-4 py-3 text-sm font-semibold">Current Lowest Bid</th>
                    <th className="px-4 py-3 text-sm font-semibold">Bid Close Time</th>
                    <th className="px-4 py-3 text-sm font-semibold">Forced Close Time</th>
                    <th className="px-4 py-3 text-sm font-semibold">Status</th>
                    <th className="px-4 py-3 text-sm font-semibold">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {rfqs.map((rfq) => (
                    <tr key={rfq.id} className="border-b border-gray-200 last:border-b-0">
                      <td className="px-4 py-3 text-sm font-medium text-gray-900">{rfq.name}</td>
                      <td className="px-4 py-3 text-sm text-gray-700">{rfq.reference_id}</td>
                      <td className="px-4 py-3 text-sm">
                        {rfq.lowest_bid == null ? (
                          <span className="text-gray-500">No bids yet</span>
                        ) : (
                          <span className="font-bold text-[#16a34a]">£{rfq.lowest_bid.toFixed(2)}</span>
                        )}
                      </td>
                      <td className="px-4 py-3 text-sm text-gray-700">{formatDateTime(rfq.bid_close_time)}</td>
                      <td className="px-4 py-3 text-sm text-gray-700">{formatDateTime(rfq.forced_close_time)}</td>
                      <td className="px-4 py-3 text-sm">{statusBadge(rfq.status)}</td>
                      <td className="px-4 py-3 text-sm">
                        <button
                          className="rounded-md bg-[#2563eb] px-3 py-1.5 text-white transition hover:bg-blue-700"
                          onClick={() => navigate(`/rfq/${rfq.id}`)}
                        >
                          View Details
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AuctionList;
